import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';

function App() {
  const [profiles, setProfiles] = useState([]);

  useEffect(() => {
    fetchProfiles();
  }, []);

  async function fetchProfiles() {
    const { data } = await supabase
      .from('profiles')
      .select('id, full_name, avatar_url, bio, primary_skill, seeking_skill')
      .limit(10);
    if (data) setProfiles(data);
  }

  return (
    <div className="min-h-screen bg-slate-50 p-8 font-sans">
      <header className="max-w-6xl mx-auto mb-12 text-center">
        <h1 className="text-4xl font-extrabold text-slate-900 mb-2">SkillSwap</h1>
        <p className="text-slate-600 text-lg">Trade talent. Scale faster. Zero cash.</p>
      </header>

      <main className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {profiles.map((profile) => (
          <div key={profile.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 hover:shadow-md transition-shadow">
            <div className="flex items-center space-x-4 mb-4">
              <img 
                src={profile.avatar_url || `https://api.dicebear.com/7.x/bottts/svg?seed=${profile.full_name}`} 
                className="w-16 h-16 rounded-full bg-slate-100" 
                alt="avatar" 
              />
              <div>
                <h2 className="text-xl font-bold text-slate-800">{profile.full_name}</h2>
                <span className="bg-blue-100 text-blue-700 text-xs font-semibold px-2.5 py-0.5 rounded-full">
                  {profile.primary_skill}
                </span>
              </div>
            </div>
            <p className="text-slate-600 text-sm line-clamp-3 mb-4">{profile.bio}</p>
            <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
              <span className="text-xs text-slate-400 uppercase tracking-wider font-semibold">Seeking: {profile.seeking_skill}</span>
              <button className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-800">
                Swap
              </button>
            </div>
          </div>
        ))}
      </main>
    </div>
  );
}

export default App;
